// USDA Plant Hardiness Zone Data (2023)
// Source: https://prism.oregonstate.edu/phzm/data/2023/phzm_us_zipcode_2023.csv
// Compressed with gzip, then base64 encoded
// Original size: ~1.2 MB, Compressed: ~112 KB, Base64: ~149 KB

const BASE64_DATA = `




`.replace(/\s+/g, '');

// Decompress gzip data using DecompressionStream
async function decompressGzip(base64Data) {
  const binaryData = Uint8Array.from(atob(base64Data), c => c.charCodeAt(0));
  const stream = new ReadableStream({
    start(controller) {
      controller.enqueue(binaryData);
      controller.close();
    }
  });
  
  const decompressedStream = stream.pipeThrough(new DecompressionStream('gzip'));
  const reader = decompressedStream.getReader();
  const chunks = [];
  
  while (true) {
    const { done, value } = await reader.read();
    if (done) break;
    chunks.push(value);
  }
  
  const totalLength = chunks.reduce((sum, chunk) => sum + chunk.length, 0);
  const result = new Uint8Array(totalLength);
  let offset = 0;
  for (const chunk of chunks) {
    result.set(chunk, offset);
    offset += chunk.length;
  }
  
  return new TextDecoder().decode(result);
}

// Parse CSV and build lookup map
function parseZoneData(csvText) {
  const lines = csvText.trim().split('\n');
  const data = new Map();
  
  for (let i = 1; i < lines.length; i++) {
    const line = lines[i].trim();
    if (!line) continue;
    
    const parts = line.split(',');
    if (parts.length >= 3) {
      const zipcode = parts[0].padStart(5, '0');
      const zone = parts[1];
      const trange = parts[2];
      const zonetitle = parts[3] || zone;
      
      data.set(zipcode, { zone, trange, zonetitle });
    }
  }
  
  return data;
}

// Zone details with growing info
const ZONE_DETAILS = {
  '1a': { tempF: '-60 to -55', tempC: '-51.1 to -48.3' },
  '1b': { tempF: '-55 to -50', tempC: '-48.3 to -45.6' },
  '2a': { tempF: '-50 to -45', tempC: '-45.6 to -42.8' },
  '2b': { tempF: '-45 to -40', tempC: '-42.8 to -40.0' },
  '3a': { tempF: '-40 to -35', tempC: '-40.0 to -37.2' },
  '3b': { tempF: '-35 to -30', tempC: '-37.2 to -34.4' },
  '4a': { tempF: '-30 to -25', tempC: '-34.4 to -31.7' },
  '4b': { tempF: '-25 to -20', tempC: '-31.7 to -28.9' },
  '5a': { tempF: '-20 to -15', tempC: '-28.9 to -26.1' },
  '5b': { tempF: '-15 to -10', tempC: '-26.1 to -23.3' },
  '6a': { tempF: '-10 to -5', tempC: '-23.3 to -20.6' },
  '6b': { tempF: '-5 to 0', tempC: '-20.6 to -17.8' },
  '7a': { tempF: '0 to 5', tempC: '-17.8 to -15.0' },
  '7b': { tempF: '5 to 10', tempC: '-15.0 to -12.2' },
  '8a': { tempF: '10 to 15', tempC: '-12.2 to -9.4' },
  '8b': { tempF: '15 to 20', tempC: '-9.4 to -6.7' },
  '9a': { tempF: '20 to 25', tempC: '-6.7 to -3.9' },
  '9b': { tempF: '25 to 30', tempC: '-3.9 to -1.1' },
  '10a': { tempF: '30 to 35', tempC: '-1.1 to 1.7' },
  '10b': { tempF: '35 to 40', tempC: '1.7 to 4.4' },
  '11a': { tempF: '40 to 45', tempC: '4.4 to 7.2' },
  '11b': { tempF: '45 to 50', tempC: '7.2 to 10.0' },
  '12a': { tempF: '50 to 55', tempC: '10.0 to 12.8' },
  '12b': { tempF: '55 to 60', tempC: '12.8 to 15.6' },
  '13a': { tempF: '60 to 65', tempC: '15.6 to 18.3' },
  '13b': { tempF: '65 to 70', tempC: '18.3 to 21.1' }
};

let zoneDataCache = null;
let dataPromise = null;

export async function getZoneData() {
  if (zoneDataCache) return zoneDataCache;
  if (dataPromise) return dataPromise;
  
  dataPromise = (async () => {
    try {
      const csvText = await decompressGzip(BASE64_DATA);
      zoneDataCache = parseZoneData(csvText);
      return zoneDataCache;
    } catch (e) {
      console.error('Failed to load zone data:', e);
      zoneDataCache = new Map();
      return zoneDataCache;
    }
  })();
  
  return dataPromise;
}

export async function getZoneByZip(zipCode) {
  const data = await getZoneData();
  const paddedZip = zipCode.toString().padStart(5, '0');
  return data.get(paddedZip);
}

export function getZoneDetails(zone) {
  return ZONE_DETAILS[zone] || null;
}

